function toText(raw) {
  if (Buffer.isBuffer(raw)) return raw.toString('utf8');
  return String(raw ?? '');
}

async function fetchNaverAdminStocks() {

  const codes = new Set();

  const urls = [
    'https://finance.naver.com/sise/management.naver',           // 
    'https://finance.naver.com/sise/management.naver?sosok=0',   // KOSPI
    'https://finance.naver.com/sise/management.naver?sosok=1',   // KOSDAQ
  ];

  for (const url of urls) {
    try {
      const raw = await http({
        method: 'GET',
        url,
        headers: NAVER_HEADERS,
        json: false,
      });

      const text = toText(raw);

      // code=XXXXXX    
      const matches = text.matchAll(/code=(\d{6})/g);
      for (const m of matches) {
        codes.add(m[1]);
      }

      await sleep(200);
    } catch (e) {
      //  URL   
    }
  }

  return [...codes];
}

