        const qty = calcQty(ACCOUNT_KRW, RISK_PCT_PER_TRADE * sizeFactor, entry, stop);

        const code = normalize(getCode(t));
        const name = NAME[code] || code;
        const market = t.endsWith('.KS') ? 'KOSPI' : 'KOSDAQ';

        const rankScore = pUP * 100 + score;

        candidates.push({
          ticker: t,
          code,
          name,
          market,
          entry,
          target,
          stop,
          score,
          signals,
          pUP,
          atrAbs,
          riskOn,
          qty,
          rankScore,
          strictPass,
          relaxedPass,
          dailyChange,
          prevClose,
          currentPrice,
        });
