  const alertMin = kst.getUTCMinutes();
  const isMarketTimeForAlert = (alertHour > 9 || (alertHour === 9 && alertMin >= 5)) && 
                               (alertHour < 15 || (alertHour === 15 && alertMin < 25));
  if (noResultAll && isMarketTimeForAlert) {
