      sendFailCount++;
      if (sendFailSamples.length < 3) sendFailSamples.push({ ticker: c.ticker, message: String(e?.message || e) });
      return false;
    }
  };

  for (const c of selected) {
    const ok = await send(c);
    if (ok) {
      store.scalpingSent[c.ticker] = now.getTime();
      store.weeklyRecommendations[today].push({
        type: 'scalping',
        subType: 'UP',
        ticker: c.ticker,
        code: c.code,
        name: c.name,
        entry: c.entry,
        target: c.target,
        stop: c.stop,
        holdingDays: 1,
        score: c.score,
        prob: c.pUP,
      });
      sent.push(c.ticker);
      await new Promise((r) => setTimeout(r, 900));
    }
  }

  if (sendFailCount > 0) {
    if (!store.telegramAlerts) store.telegramAlerts = {};
    const last = Number(store.telegramAlerts.scalpingSendFailAt || 0);
    const nowMs = Date.now();
    if (nowMs - last > 30 * 60 * 1000) {
      const sample = (sendFailSamples && sendFailSamples.length) ? JSON.stringify(sendFailSamples.slice(0, 2)) : 'none';
      const msg = 'вҡ пёҸ [л°ңмҶЎ мҳӨлҘҳ] лӢЁнғҖ м•ҢлҰј м „мҶЎ мӢӨнҢЁ' + NL +
        `- KST: ${today} ${timeStrNow}` + NL +
        `- failCount: ${sendFailCount}` + NL +
        `- sample: ${sample}`;
      try { await http({ method: 'POST', url: 'https://api.telegram.org/bot' + BOT + '/sendMessage', json: true, body: { chat_id: CHAT, text: msg } }); } catch (e) {}
      store.telegramAlerts.scalpingSendFailAt = nowMs;
    }
  }

  // 0кұҙ м•ҲлӮҙ м•ҢлҰј(н•ҳлЈЁ 1нҡҢ): м¶”мІңмқҙ м—Ҷм–ҙлҸ„ мӮ¬мҡ©мһҗм—җкІҢ 'м •мғҒ лҸҷмһ‘ + 0кұҙ'мқ„ м•Ңл ӨмӨҚлӢҲлӢӨ.
  if (!store.scalpingAlerts) store.scalpingAlerts = {};
  if (sent.length === 0 && store.scalpingAlerts.noHitDate !== today) {
    const msg =
      'в„№пёҸ [лӢЁнғҖ] мҳӨлҠҳ мЎ°кұҙмқ„ л§ҢмЎұн•ң мў…лӘ©мқҙ м•„м§Ғ м—ҶмҠөлӢҲлӢӨ(0кұҙ)' + NL +
      `- KST: ${today} ${timeStrNow}` + NL +
      `- мң лӢҲлІ„мҠӨ(н•„н„° нӣ„): ${ALL_TICKERS.length}к°ң` + NL +
      `- нӣ„ліҙ: ${candidates.length}кұҙ` + NL +
      `- м ңмҷё(лҰ¬мҠӨнҒ¬): ${excludedRisk}к°ң` + NL +
      `- м ңмҷё(н…Ңл§Ҳ): ${excludedTheme}к°ң` + NL +
      `- Naver OK/NoResult/Error: ${naverOkCount}/${naverNoResultCount}/${naverErrorCount}`;
    try { await http({ method: 'POST', url: 'https://api.telegram.org/bot' + BOT + '/sendMessage', json: true, body: { chat_id: CHAT, text: msg } }); } catch (e) {}
    store.scalpingAlerts.noHitDate = today;
  }

  // Debug summary
  if (debugMode) {
    const msg =
      'рҹ”Қ [лӢЁнғҖ л””лІ„к·ё] мҠӨмә” мҷ„лЈҢ' + NL +
      `- л°ңкІ¬(нӣ„ліҙ): ${candidates.length}кұҙ` + NL +
      `- л°ңмҶЎ: ${sent.length}кұҙ` + NL +
      `- мң лӢҲлІ„мҠӨ(н•„н„° нӣ„): ${ALL_TICKERS.length}к°ң` + NL +
      `- м ңмҷё(лҰ¬мҠӨнҒ¬): ${excludedRisk}к°ң` + NL +
      `- м ңмҷё(н…Ңл§Ҳ): ${excludedTheme}к°ң` + NL +
      `- Naver OK/NoResult/Error: ${naverOkCount}/${naverNoResultCount}/${naverErrorCount}` + NL +
      `- Naver err status: ${Object.keys(naverErrorByStatus).slice(0,4).map(k=>k+':'+naverErrorByStatus[k]).join(', ') || 'none'}` + NL +
      `- riskCacheAt: ${riskCacheAt || 'null'}` + NL +
      `- themeCacheAt: ${themeCacheAt || 'null'}` + NL +
      `- KST: ${today} ${timeStrNow}`;
    try { await http({ method: 'POST', url: 'https://api.telegram.org/bot' + BOT + '/sendMessage', json: true, body: { chat_id: CHAT, text: msg } }); } catch (e) {}
  }

  store.scalpingMeta._lastFullFinish = Date.now(); // [PERF] Queue м ҒмІҙ л°©м§Җмҡ©
  return [{
    json: {
      ok: true,
      scanTime: kst.toISOString(),
      totalUniverse: ALL_TICKERS.length,
      candidates: candidates.length,
      sent: sent.length,
      sentTickers: sent,
      excludedRisk,
      excludedTheme,
      riskCacheAt,
      themeCacheAt,
      naverOkCount,
      naverNoResultCount,
      naverErrorCount,
      naverErrorByStatus,
      naverErrorSamples,
    }
  }];
};

return run();

