          if (nPattern) {
            score += 40;
            signals.push('Nмһҗнҳ•лҲҢлҰјлӘ©');
          }

          // мҠӨмңҷмқҖ мһҘмӨ‘ кұ°лһҳлҢҖкёҲ н•„н„°(мӣҗліё мң м§Җ)
          // (мЈјмқҳ: м—¬кё°м„ңмқҳ turnoverлҠ” KRX кё°мӨҖмңјлЎң мқҙлҜё 1м°Ё н•„н„°л§Ғн–Ҳкё° л•Ңл¬ём—җ м¶”к°Җ кі„мӮ°мқҖ мғқлһө)

          if (score < RELAX_SCORE) return;

          const type = 'мҠӨмңҷ';
          const entry = currentPrice;

          // HiTalk setup scoring (MAT=мҠӨмңҷ/мһ¬лЈҢ мҠӨнғҖмқј)
          const featIdx = Math.max(60, Math.min(idxToday >= 0 ? idxToday : dIdx, closeD.length - 1));
