      // code=XXXXXX нҢЁн„ҙмңјлЎң мў…лӘ© мҪ”л“ң м¶”м¶ң
      const matches = text.matchAll(/code=(\d{6})/g);
      for (const m of matches) {
        codes.add(m[1]);
      }

      await sleep(200);
    } catch (e) {
      // к°ңлі„ URL мӢӨнҢЁлҠ” л¬ҙмӢңн•ҳкі  кі„мҶҚ
    }
  }

  return [...codes];
}

// KIND мӢӨм§ҲмӢ¬мӮ¬лІ•мқё (кё°мЎҙ лЎңм§Ғ мң м§Җ - мқҙкұҙ мһ‘лҸҷн•  мҲҳ мһҲмқҢ)
async function fetchKindRealInvestigationCodes() {
  try {
    const url = 'https://kind.krx.co.kr/corpgeneral/delistRealInvstg.do';
    const form = {
      method: 'searchDelistRealInvstg',
      forward: 'delistRealInvstg_down',
      pageIndex: '1',
      currentPageSize: '3000',
      mktTpCd: '',
      progrsDelistYn: '',
      fromDate: '',
      toDate: '',
    };

    const body = Object.entries(form)
      .map(([k, v]) => encodeURIComponent(k) + '=' + encodeURIComponent(v))
      .join('&');

    const raw = await http({
      method: 'POST',
      url,
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Origin': 'https://kind.krx.co.kr',
        'Referer': 'https://kind.krx.co.kr/corpgeneral/delistRealInvstg.do?method=searchDelistRealInvstgMain',
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
        'Accept-Language': 'ko-KR,ko;q=0.9,en;q=0.8',
      },
      body,
      json: false,
    });

    const text = Buffer.isBuffer(raw) ? raw.toString('latin1') : String(raw);
    const set = new Set();
    for (const m of text.matchAll(/mso-number-format:'@'[^>]*>\s*(\d{6})\s*<\/td>/g)) {
      set.add(m[1]);
    }
    return [...set];
  } catch (e) {
    return [];
  }
}

try {
  const codes = new Set();
  const sourceCounts = {};

  // 1. л„ӨмқҙлІ„ кёҲмңө кҙҖлҰ¬мў…лӘ©
  const naverAdminCodes = await fetchNaverAdminStocks();
  sourceCounts['Naver:adminStocks'] = naverAdminCodes.length;
  for (const c of naverAdminCodes) codes.add(c);

  // 2. KIND мӢӨм§ҲмӢ¬мӮ¬лІ•мқё (best-effort)
  const kindCodes = await fetchKindRealInvestigationCodes();
  sourceCounts['KIND:realInvestigation'] = kindCodes.length;
  for (const c of kindCodes) codes.add(c);

  // мөңмҶҢ 1к°ң мқҙмғҒмқҳ мҪ”л“ңк°Җ мһҲм–ҙм•ј м„ұкіө
  if (codes.size === 0 && prev.riskCodes && prev.riskCodes.length > 0) {
    await notifyOncePerDay(
      'risk_blacklist_empty_keep_cache',
      '[лҰ¬мҠӨнҒ¬ лё”лһҷлҰ¬мҠӨнҠё] мӢ к·ң лҚ°мқҙн„° 0кұҙ - кё°мЎҙ мәҗмӢң мң м§Җ' + NL +
      '- кё°мЎҙ мәҗмӢң: ' + prev.riskCodes.length + 'к°ң' + NL +
      '- л§Ҳм§Җл§ү к°ұмӢ : ' + prev.riskUpdatedAt
    );
    return [{ json: { ok: true, keptCache: true, riskCodesCount: prev.riskCodes.length, riskUpdatedAt: prev.riskUpdatedAt } }];
  }

  store.blacklist.riskCodes = [...codes].sort();
  store.blacklist.riskUpdatedAt = new Date().toISOString();
  store.blacklist.riskSourceCounts = sourceCounts;
  store.blacklist.riskSource = 'Naver+KIND';

  // м„ұкіө мӢң м—җлҹ¬ мғҒнғң нҒҙлҰ¬м–ҙ
  delete store.blacklist.riskLastError;

  // м„ұкіө м•ҢлҰј
  await notifyOncePerDay(
    'risk_blacklist_success',
    '[лҰ¬мҠӨнҒ¬ лё”лһҷлҰ¬мҠӨнҠё к°ұмӢ  м„ұкіө]' + NL +
    '- мҙқ ' + store.blacklist.riskCodes.length + 'к°ң мў…лӘ©' + NL +
    '- л„ӨмқҙлІ„: ' + naverAdminCodes.length + 'к°ң' + NL +
    '- KIND: ' + kindCodes.length + 'к°ң' + NL +
    '- к°ұмӢ  мӢңк°„: ' + store.blacklist.riskUpdatedAt
  );

  return [
    {
      json: {
        ok: true,
        riskCodesCount: store.blacklist.riskCodes.length,
        riskSourceCounts: sourceCounts,
        riskUpdatedAt: store.blacklist.riskUpdatedAt,
        source: 'Naver+KIND',
      },
    },
  ];
} catch (e) {
  const msg = e?.message ? String(e.message) : String(e);
  openCircuit(msg);
  store.blacklist.riskLastError = { at: new Date().toISOString(), message: msg };

  // кё°мЎҙ к°’ мң м§Җ
  if (prev.riskCodes) store.blacklist.riskCodes = prev.riskCodes;
  if (prev.riskUpdatedAt) store.blacklist.riskUpdatedAt = prev.riskUpdatedAt;
  if (prev.riskSourceCounts) store.blacklist.riskSourceCounts = prev.riskSourceCounts;

  await notifyOncePerDay('risk_blacklist_fail', '[лҰ¬мҠӨнҒ¬ лё”лһҷлҰ¬мҠӨнҠё к°ұмӢ  мӢӨнҢЁ]' + NL + msg);
  return [{ json: { ok: false, error: msg, riskUpdatedAt: store.blacklist.riskUpdatedAt || null } }];
}

const store = this.getWorkflowStaticData('global');
if (!store.blacklist) store.blacklist = {};

const http = async (o) =>
  await this.helpers.httpRequest(
    Object.assign(
      {
        timeout: 30000,
      },
      o
    )
  );

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

function toText(raw) {
  if (Buffer.isBuffer(raw)) return raw.toString('utf8');
  return String(raw ?? '');
}

async function fetchText(url, referer) {
  const raw = await http({
    method: 'GET',
    url,
    headers: {
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
      Referer: referer || 'https://finance.naver.com/',
      'Accept-Language': 'ko-KR,ko;q=0.9,en;q=0.8',
    },
    json: false,
  });
  return toText(raw);
}

async function fetchTextRetry(url, referer, tries = 2) {
  let lastErr;
  for (let i = 0; i < tries; i++) {
    try {
      return await fetchText(url, referer);
    } catch (e) {
      lastErr = e;
      await sleep(300 + i * 500);
    }
  }
  throw lastErr;
}

function uniq(arr) {
  return [...new Set(arr)];
}

function extractThemeNos(html) {
  // /sise/sise_group_detail.naver?type=theme&no=584
  return uniq([...html.matchAll(/sise_group_detail\.naver\?type=theme&no=(\d+)/g)].map((m) => m[1]));
}

function extractCodes(html) {
  // /item/main.naver?code=005930
  return uniq([...html.matchAll(/code=(\d{6})/g)].map((m) => m[1]));
}

async function mapLimit(list, limit, worker) {
  const results = [];
  const errors = [];
  let idx = 0;

  const runners = new Array(Math.min(limit, list.length)).fill(0).map(async () => {
    while (idx < list.length) {
      const i = idx++;
      try {
        results[i] = await worker(list[i], i);
      } catch (e) {
        errors.push({ i, item: list[i], message: e?.message || String(e) });
        results[i] = null;
      }
    }
  });

  await Promise.all(runners);
  return { results, errors };
}

// ====== нҠңлӢқ нҸ¬мқёнҠё(м°ЁлӢЁ/лҠҗлҰјмқҙл©ҙ м—¬кё°л§Ң мЎ°м Ҳ) ======
const MAX_LIST_PAGES = 20;     // н…Ңл§Ҳ лӘ©лЎқ нҺҳмқҙм§Җ мөңлҢҖ нғҗмғү
const CONCURRENCY = 6;         // н…Ңл§Ҳ мғҒм„ё лҸҷмӢң мҡ”мІӯ мҲҳ (м°ЁлӢЁлҗҳл©ҙ 3мңјлЎң лӮ®м¶”м„ёмҡ”)
const DETAIL_SLEEP_MS = 120;   // мғҒм„ё мҡ”мІӯ мӮ¬мқҙ м•„мЈј м§§мқҖ н…Җ(м°ЁлӢЁ мҷ„нҷ”)
const LIST_SLEEP_MS = 120;     // лӘ©лЎқ нҺҳмқҙм§Җ мҡ”мІӯ н…Җ
// =====================================================

const startTs = Date.now();
const baseList = 'https://finance.naver.com/sise/theme.naver';
const listReferer = 'https://finance.naver.com/sise/theme.naver';

// 1) н…Ңл§Ҳ no лӘ©лЎқ мҲҳм§‘
const html1 = await fetchTextRetry(`${baseList}?&page=1`, listReferer, 2);
let themeNos = extractThemeNos(html1);

if (themeNos.length === 0) {
  return [
    {
      json: {
        ok: false,
        reason: 'No theme no found on list page (expected type=theme&no=###)',
        lenUtf8: html1.length,
        snippet: html1.slice(0, 1200),
      },
    },
  ];
}

// нҺҳмқҙм§Җ мҲҳ м¶”м •
const pagesFound = uniq([...html1.matchAll(/page=(\d+)/g)].map((m) => Number(m[1]) || 1)).filter((n) => n >= 1);
let maxPage = pagesFound.length ? Math.max(...pagesFound) : MAX_LIST_PAGES;
maxPage = Math.min(maxPage, MAX_LIST_PAGES);

const allNos = new Set(themeNos);
let stoppedEarlyAtPage = null;

for (let p = 2; p <= maxPage; p++) {
  await sleep(LIST_SLEEP_MS);
  const html = await fetchTextRetry(`${baseList}?&page=${p}`, listReferer, 2);
  const nos = extractThemeNos(html);

  let added = 0;
  for (const no of nos) {
    if (!allNos.has(no)) {
      allNos.add(no);
      added++;
    }
  }

  if (added === 0 && p >= 3) {
    stoppedEarlyAtPage = p;
    break;
  }
}

themeNos = [...allNos].sort((a, b) => Number(a) - Number(b));

// 2) н…Ңл§Ҳ мғҒм„ём—җм„ң мў…лӘ©мҪ”л“ң мҲҳм§‘(лҸҷмӢңмІҳлҰ¬)
const codeSet = new Set();
const detailErrors = [];

const detailReferer = 'https://finance.naver.com/sise/theme.naver';
const { errors } = await mapLimit(themeNos, CONCURRENCY, async (no) => {
  await sleep(DETAIL_SLEEP_MS);
  const url = `https://finance.naver.com/sise/sise_group_detail.naver?type=theme&no=${no}`;
  const html = await fetchTextRetry(url, detailReferer, 2);
  const codes = extractCodes(html);
  for (const c of codes) codeSet.add(c);
  return { no, codesCount: codes.length };
});

if (errors.length) detailErrors.push(...errors);

// 3) м ҖмһҘ + лҰ¬н„ҙ
const themeCodes = [...codeSet].sort();

store.blacklist.themeCodes = themeCodes;
store.blacklist.themeUpdatedAt = new Date().toISOString();
store.blacklist.themeNosCount = themeNos.length;
store.blacklist.themeSource = 'naver:sise_group_detail';
store.blacklist.themeFetchStats = {
  stoppedEarlyAtPage,
  maxPageTried: maxPage,
  concurrency: CONCURRENCY,
  detailErrors: detailErrors.length,
  ms: Date.now() - startTs,
};

return [
  {
    json: {
      ok: true,
      done: true,
      themeNosCount: themeNos.length,
      themeCodesCount: themeCodes.length,
      themeUpdatedAt: store.blacklist.themeUpdatedAt,
      stats: store.blacklist.themeFetchStats,
      sampleCodes: themeCodes.slice(0, 20),
      detailErrors: detailErrors.slice(0, 10),
    },
  },
];
